program LaunchInterceptor;

uses
  SysUtils, JSON;

const
  PI = 3.1415926535;

type
  COMPTYPE = (LT, EQ, GT);
  CONNECTORS = (NOTUSED, ORR, ANDD);
  COORDINATE = array[1..100] of real;
  CMATRIX = array[1..15, 1..15] of CONNECTORS;
  BMATRIX = array[1..15, 1..15] of boolean;
  VECTOR = array[1..15] of boolean;

var
  X, Y: COORDINATE;
  NUMPOINTS: integer;
  LENGTH1, RADIUS1, EPSILON, AREA1, DIST: real;
  Q_PTS, QUADS: integer;
  N_PTS, K_PTS, A_PTS, B_PTS, C_PTS, D_PTS, E_PTS, F_PTS, G_PTS: integer;
  LENGTH2, RADIUS2, AREA2: real;
  LCM: CMATRIX;
  PUM: BMATRIX;
  CMV: VECTOR;
  FUV: VECTOR;
  LAUNCH: boolean;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

function Distance(i, j: integer): real;
begin
  Distance := Sqrt(Sqr(X[i] - X[j]) + Sqr(Y[i] - Y[j]));
end;

function TriangleArea(i, j, k: integer): real;
begin
  TriangleArea := 0.5 * Abs((X[j] - X[i]) * (Y[k] - Y[i]) - (X[k] - X[i]) * (Y[j] - Y[i]));
end;

function Angle(i, j, k: integer): real;
var
  dx1, dy1, dx2, dy2, mag1, mag2, dot: real;
begin
  dx1 := X[i] - X[j];
  dy1 := Y[i] - Y[j];
  dx2 := X[k] - X[j];
  dy2 := Y[k] - Y[j];
  mag1 := Sqrt(Sqr(dx1) + Sqr(dy1));
  mag2 := Sqrt(Sqr(dx2) + Sqr(dy2));
  if (mag1 = 0) or (mag2 = 0) then
  begin
    Angle := -1;
    Exit;
  end;
  dot := dx1 * dx2 + dy1 * dy2;
  Angle := ArcTan2(dot, mag1 * mag2);
  if Angle < 0 then
    Angle := -Angle;
end;

function CircleRadius(i, j, k: integer): real;
var
  a, b, c, s, area: real;
begin
  a := Distance(j, k);
  b := Distance(i, k);
  c := Distance(i, j);
  if (a = 0) or (b = 0) or (c = 0) then
  begin
    CircleRadius := 0;
    Exit;
  end;
  s := (a + b + c) / 2;
  area := Sqrt(s * (s - a) * (s - b) * (s - c));
  if area = 0 then
  begin
    CircleRadius := 0;
    Exit;
  end;
  CircleRadius := (a * b * c) / (4 * area);
end;

function Quadrant(x, y: real): integer;
begin
  if (x > 0) and (y >= 0) then
    Quadrant := 1
  else if (x <= 0) and (y > 0) then
    Quadrant := 2
  else if (x < 0) and (y <= 0) then
    Quadrant := 3
  else
    Quadrant := 1;
end;

function EvaluateLIC1: boolean;
var
  i: integer;
begin
  EvaluateLIC1 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if Distance(i, i + 1) > LENGTH1 then
    begin
      EvaluateLIC1 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC2: boolean;
var
  i: integer;
begin
  EvaluateLIC2 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if CircleRadius(i, i + 1, i + 2) > RADIUS1 then
    begin
      EvaluateLIC2 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC3: boolean;
var
  i: integer;
  angle: real;
begin
  EvaluateLIC3 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    angle := Angle(i, i + 1, i + 2);
    if angle < 0 then
      continue;
    if (angle < (PI - EPSILON)) or (angle > (PI + EPSILON)) then
    begin
      EvaluateLIC3 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC4: boolean;
var
  i: integer;
begin
  EvaluateLIC4 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if TriangleArea(i, i + 1, i + 2) > AREA1 then
    begin
      EvaluateLIC4 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC5: boolean;
var
  i, quad_count, q1, q2, q3, q4: integer;
begin
  EvaluateLIC5 := false;
  for i := 1 to NUMPOINTS - Q_PTS + 1 do
  begin
    q1 := 0; q2 := 0; q3 := 0; q4 := 0;
    quad_count := 0;
    if Quadrant(X[i], Y[i]) = 1 then q1 := 1 else if Quadrant(X[i], Y[i]) = 2 then q2 := 1 else if Quadrant(X[i], Y[i]) = 3 then q3 := 1 else q4 := 1;
    for j := 1 to Q_PTS - 1 do
    begin
      case Quadrant(X[i + j], Y[i + j]) of
        1: q1 := 1;
        2: q2 := 1;
        3: q3 := 1;
        4: q4 := 1;
      end;
    end;
    quad_count := q1 + q2 + q3 + q4;
    if quad_count > QUADS then
    begin
      EvaluateLIC5 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC6: boolean;
var
  i: integer;
begin
  EvaluateLIC6 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if X[i + 1] - X[i] < 0 then
    begin
      EvaluateLIC6 := true;
      Exit;
    end;
  end;
end;

function PointToLineDistance(px, py, x1, y1, x2, y2: real): real;
var
  dx, dy, num: real;
begin
  dx := x2 - x1;
  dy := y2 - y1;
  if (dx = 0) and (dy = 0) then
  begin
    PointToLineDistance := Sqrt(Sqr(px - x1) + Sqr(py - y1));
    Exit;
  end;
  num := Abs(dy * px - dx * py + x2 * y1 - y2 * x1);
  PointToLineDistance := num / Sqrt(Sqr(dx) + Sqr(dy));
end;

function EvaluateLIC7: boolean;
var
  i, j: integer;
  max_dist: real;
begin
  EvaluateLIC7 := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - N_PTS + 1 do
  begin
    max_dist := 0;
    for j := 0 to N_PTS - 1 do
    begin
      if N_PTS = 2 then
        max_dist := Max(max_dist, Distance(i, i + j))
      else
        max_dist := Max(max_dist, PointToLineDistance(X[i + j], Y[i + j], X[i], Y[i], X[i + N_PTS - 1], Y[i + N_PTS - 1]));
    end;
    if max_dist > DIST then
    begin
      EvaluateLIC7 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC8: boolean;
var
  i: integer;
begin
  EvaluateLIC8 := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - K_PTS - 1 do
  begin
    if Distance(i, i + K_PTS + 1) > LENGTH1 then
    begin
      EvaluateLIC8 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC9: boolean;
var
  i: integer;
begin
  EvaluateLIC9 := false;
  if NUMPOINTS < 5 then
    Exit;
  for i := 1 to NUMPOINTS - A_PTS - B_PTS - 2 do
  begin
    if CircleRadius(i, i + A_PTS + 1, i + A_PTS + B_PTS + 2) > RADIUS1 then
    begin
      EvaluateLIC9 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC10: boolean;
var
  i: integer;
  angle: real;
begin
  EvaluateLIC10 := false;
  if NUMPOINTS < 5 then
    Exit;
  for i := 1 to NUMPOINTS - C_PTS - D_PTS - 2 do
  begin
    angle := Angle(i, i + C_PTS + 1, i + C_PTS + D_PTS + 2);
    if angle < 0 then
      continue;
    if (angle < (PI - EPSILON)) or (angle > (PI + EPSILON)) then
    begin
      EvaluateLIC10 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC11: boolean;
var
  i: integer;
begin
  EvaluateLIC11 := false;
  if NUMPOINTS < 5 then
    Exit;
  for i := 1 to NUMPOINTS - E_PTS - F_PTS - 2 do
  begin
    if TriangleArea(i, i + E_PTS + 1, i + E_PTS + F_PTS + 2) > AREA1 then
    begin
      EvaluateLIC11 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC12: boolean;
var
  i: integer;
begin
  EvaluateLIC12 := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - G_PTS - 1 do
  begin
    if X[i + G_PTS + 1] - X[i] < 0 then
    begin
      EvaluateLIC12 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC13: boolean;
var
  i, j: integer;
  has_greater, has_less: boolean;
begin
  EvaluateLIC13 := false;
  if NUMPOINTS < 3 then
    Exit;
  has_greater := false;
  has_less := false;
  for i := 1 to NUMPOINTS - K_PTS - 1 do
  begin
    if Distance(i, i + K_PTS + 1) > LENGTH1 then
      has_greater := true;
    if Distance(i, i + K_PTS + 1) < LENGTH2 then
      has_less := true;
  end;
  EvaluateLIC13 := has_greater and has_less;
end;

function EvaluateLIC14: boolean;
var
  i, j: integer;
  has_outside, has_inside: boolean;
begin
  EvaluateLIC14 := false;
  if NUMPOINTS < 5 then
    Exit;
  has_outside := false;
  has_inside := false;
  for i := 1 to NUMPOINTS - A_PTS - B_PTS - 2 do
  begin
    if CircleRadius(i, i + A_PTS + 1, i + A_PTS + B_PTS + 2) > RADIUS1 then
      has_outside := true;
    if CircleRadius(i, i + A_PTS + 1, i + A_PTS + B_PTS + 2) <= RADIUS2 then
      has_inside := true;
  end;
  EvaluateLIC14 := has_outside and has_inside;
end;

function EvaluateLIC15: boolean;
var
  i, j: integer;
  has_greater, has_less: boolean;
begin
  EvaluateLIC15 := false;
  if NUMPOINTS < 5 then
    Exit;
  has_greater := false;
  has_less := false;
  for i := 1 to NUMPOINTS - E_PTS - F_PTS - 2 do
  begin
    if TriangleArea(i, i + E_PTS + 1, i + E_PTS + F_PTS + 2) > AREA1 then
      has_greater := true;
    if TriangleArea(i, i + E_PTS + 1, i + E_PTS + F_PTS + 2) < AREA2 then
      has_less := true;
  end;
  EvaluateLIC15 := has_greater and has_less;
end;

procedure DECIDE;
var
  i, j: integer;
  all_true: boolean;
  row_all_true: boolean;
begin
  CMV[1] := EvaluateLIC1;
  CMV[2] := EvaluateLIC2;
  CMV[3] := EvaluateLIC3;
  CMV[4] := EvaluateLIC4;
  CMV[5] := EvaluateLIC5;
  CMV[6] := EvaluateLIC6;
  CMV[7] := EvaluateLIC7;
  CMV[8] := EvaluateLIC8;
  CMV[9] := EvaluateLIC9;
  CMV[10] := EvaluateLIC10;
  CMV[11] := EvaluateLIC11;
  CMV[12] := EvaluateLIC12;
  CMV[13] := EvaluateLIC13;
  CMV[14] := EvaluateLIC14;
  CMV[15] := EvaluateLIC15;

  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i = j then
      begin
        PUM[i, j] := false;
      end
      else if LCM[i, j] = NOTUSED then
        PUM[i, j] := true
      else if LCM[i, j] = ANDD then
        PUM[i, j] := CMV[i] and CMV[j]
      else if LCM[i, j] = ORR then
        PUM[i, j] := CMV[i] or CMV[j];
    end;
  end;

  for i := 1 to 15 do
  begin
    all_true := true;
    row_all_true := true;
    for j := 1 to 15 do
    begin
      if not PUM[i, j] then
        all_true := false;
      if i = j then
      begin
        if PUM[i, j] then
          row_all_true := false;
      end;
    end;
    if (PUM[i, i] = false) or all_true then
      FUV[i] := true
    else
      FUV[i] := false;
  end;

  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      Exit;
    end;
  end;
end;

procedure ParseJSONInput(const JSONStr: string);
var
  J: TJSONObject;
  JArr: TJSONArray;
  JObj: TJSONObject;
  i: integer;
begin
  J := TJSONObject.ParseJSONValue(JSONStr) as TJSONObject;
  try
    NUMPOINTS := J.Get('numpoints').GetValue<integer>;
    JArr := J.Get('x').GetValue<TJSONArray>;
    for i := 0 to JArr.Count - 1 do
      X[i + 1] := JArr.GetValue<real>(i);
    JArr := J.Get('y').GetValue<TJSONArray>;
    for i := 0 to JArr.Count - 1 do
      Y[i + 1] := JArr.GetValue<real>(i);

    JObj := J.Get('parameters').GetValue<TJSONObject>;
    LENGTH1 := JObj.Get('LENGTH1').GetValue<real>;
    RADIUS1 := JObj.Get('RADIUS1').GetValue<real>;
    EPSILON := JObj.Get('EPSILON').GetValue<real>;
    AREA1 := JObj.Get('AREA1').GetValue<real>;
    Q_PTS := JObj.Get('Q_PTS').GetValue<integer>;
    QUADS := JObj.Get('QUADS').GetValue<integer>;
    DIST := JObj.Get('DIST').GetValue<real>;
    N_PTS := JObj.Get('N_PTS').GetValue<integer>;
    K_PTS := JObj.Get('K_PTS').GetValue<integer>;
    A_PTS := JObj.Get('A_PTS').GetValue<integer>;
    B_PTS := JObj.Get('B_PTS').GetValue<integer>;
    C_PTS := JObj.Get('C_PTS').GetValue<integer>;
    D_PTS := JObj.Get('D_PTS').GetValue<integer>;
    E_PTS := JObj.Get('E_PTS').GetValue<integer>;
    F_PTS := JObj.Get('F_PTS').GetValue<integer>;
    G_PTS := JObj.Get('G_PTS').GetValue<integer>;
    LENGTH2 := JObj.Get('LENGTH2').GetValue<real>;
    RADIUS2 := JObj.Get('RADIUS2').GetValue<real>;
    AREA2 := JObj.Get('AREA2').GetValue<real>;

    JArr := J.Get('lcm').GetValue<TJSONArray>;
    for i := 0 to 14 do
    begin
      JObj := JArr.GetValue<TJSONObject>(i);
      for j := 0 to 14 do
      begin
        if JObj.GetValue<string>(j) = 'NOTUSED' then
          LCM[i + 1, j + 1] := NOTUSED
        else if JObj.GetValue<string>(j) = 'ORR' then
          LCM[i + 1, j + 1] := ORR
        else
          LCM[i + 1, j + 1] := ANDD;
      end;
    end;

    JArr := J.Get('pum_diag').GetValue<TJSONArray>;
    for i := 0 to 14 do
      PUM[i + 1, i + 1] := JArr.GetValue<boolean>(i);
  finally
    J.Free;
  end;
end;

function GenerateJSONOutput: string;
var
  J: TJSONObject;
  JArr: TJSONArray;
  i, j: integer;
begin
  J := TJSONObject.Create;
  try
    JArr := TJSONArray.Create;
    for i := 1 to 15 do
      JArr.Add(CMV[i]);
    J.AddPair('cmv', JArr);

    JArr := TJSONArray.Create;
    for i := 1 to 15 do
    begin
      JObj := TJSONObject.Create;
      for j := 1 to 15 do
        JObj.Add(PUM[i, j]);
      JArr.Add(JObj);
    end;
    J.AddPair('pum', JArr);

    JArr := TJSONArray.Create;
    for i := 1 to 15 do
      JArr.Add(FUV[i]);
    J.AddPair('fuv', JArr);

    J.AddPair('launch', LAUNCH);
    Result := J.ToJSON;
  finally
    J.Free;
  end;
end;

var
  InputStr: string;
  OutputStr: string;
  Line: string;
begin
  Line := '';
  while Readln(Line) do
    Line := Line + #10;
  if Length(Line) > 0 then
    Delete(Line, Length(Line), 1);
  InputStr := Line;

  ParseJSONInput(InputStr);
  DECIDE;
  OutputStr := GenerateJSONOutput;
  WriteLn(OutputStr);
end.

program LaunchInterceptor;

