  N_PTS, K_PTS, A_PTS, B_PTS, C_PTS, D_PTS, E_PTS, F_PTS, G_PTS: integer;
  LENGTH2, RADIUS2, AREA2: real;
  LCM: CMATRIX;
  PUM: BMATRIX;
  CMV: VECTOR;
  FUV: VECTOR;
  LAUNCH: boolean;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

function Distance(i, j: integer): real;
begin
  Distance := Sqrt(Sqr(X[i] - X[j]) + Sqr(Y[i] - Y[j]));
end;

function TriangleArea(i, j, k: integer): real;
begin
  TriangleArea := 0.5 * Abs((X[j] - X[i]) * (Y[k] - Y[i]) - (X[k] - X[i]) * (Y[j] - Y[i]));
end;

function Angle(i, j, k: integer): real;
var
  dx1, dy1, dx2, dy2, mag1, mag2, dot: real;
begin
  dx1 := X[i] - X[j];
  dy1 := Y[i] - Y[j];
  dx2 := X[k] - X[j];
  dy2 := Y[k] - Y[j];
  mag1 := Sqrt(Sqr(dx1) + Sqr(dy1));
  mag2 := Sqrt(Sqr(dx2) + Sqr(dy2));
  if (mag1 = 0) or (mag2 = 0) then
  begin
    Angle := -1;
    Exit;
  end;
  dot := dx1 * dx2 + dy1 * dy2;
  Angle := ArcTan2(dot, mag1 * mag2);
  if Angle < 0 then
    Angle := -Angle;
end;

function CircleRadius(i, j, k: integer): real;
var
  a, b, c, s, area: real;
begin
  a := Distance(j, k);
  b := Distance(i, k);
  c := Distance(i, j);
  if (a = 0) or (b = 0) or (c = 0) then
  begin
    CircleRadius := 0;
    Exit;
  end;
  s := (a + b + c) / 2;
  area := Sqrt(s * (s - a) * (s - b) * (s - c));
  if area = 0 then
  begin
    CircleRadius := 0;
    Exit;
  end;
  CircleRadius := (a * b * c) / (4 * area);
end;

function Quadrant(x, y: real): integer;
begin
  if (x > 0) and (y >= 0) then
    Quadrant := 1
  else if (x <= 0) and (y > 0) then
    Quadrant := 2
  else if (x < 0) and (y <= 0) then
    Quadrant := 3
  else
    Quadrant := 1;
end;

function EvaluateLIC1: boolean;
var
  i: integer;
begin
  EvaluateLIC1 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if Distance(i, i + 1) > LENGTH1 then
    begin
      EvaluateLIC1 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC2: boolean;
var
  i: integer;
begin
  EvaluateLIC2 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if CircleRadius(i, i + 1, i + 2) > RADIUS1 then
    begin
      EvaluateLIC2 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC3: boolean;
var
  i: integer;
  angle: real;
begin
  EvaluateLIC3 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    angle := Angle(i, i + 1, i + 2);
    if angle < 0 then
      continue;
    if (angle < (PI - EPSILON)) or (angle > (PI + EPSILON)) then
    begin
      EvaluateLIC3 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC4: boolean;
var
  i: integer;
begin
  EvaluateLIC4 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if TriangleArea(i, i + 1, i + 2) > AREA1 then
    begin
      EvaluateLIC4 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC5: boolean;
var
  i, quad_count, q1, q2, q3, q4: integer;
begin
  EvaluateLIC5 := false;
  for i := 1 to NUMPOINTS - Q_PTS + 1 do
  begin
    q1 := 0; q2 := 0; q3 := 0; q4 := 0;
    case Quadrant(X[i], Y[i]) of
      1: q1 := 1;
      2: q2 := 1;
      3: q3 := 1;
      4: q4 := 1;
    end;
    for j := 1 to Q_PTS - 1 do
      case Quadrant(X[i + j], Y[i + j]) of
        1: q1 := 1;
        2: q2 := 1;
        3: q3 := 1;
        4: q4 := 1;
      end;
    quad_count := q1 + q2 + q3 + q4;
    if quad_count > QUADS then
    begin
      EvaluateLIC5 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC6: boolean;
var
  i: integer;
begin
  EvaluateLIC6 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if X[i + 1] - X[i] < 0 then
    begin
      EvaluateLIC6 := true;
      Exit;
    end;
  end;
end;

function PointToLineDistance(px, py, x1, y1, x2, y2: real): real;
var
  dx, dy, num: real;
begin
  dx := x2 - x1;
  dy := y2 - y1;
  if (dx = 0) and (dy = 0) then
  begin
    PointToLineDistance := Sqrt(Sqr(px - x1) + Sqr(py - y1));
    Exit;
  end;
  num := Abs(dy * px - dx * py + x2 * y1 - y2 * x1);
  PointToLineDistance := num / Sqrt(Sqr(dx) + Sqr(dy));
end;

function EvaluateLIC7: boolean;
var
  i, j: integer;
  max_dist: real;
begin
  EvaluateLIC7 := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - N_PTS + 1 do
  begin
    max_dist := 0;
    for j := 0 to N_PTS - 1 do
      max_dist := Max(max_dist, PointToLineDistance(X[i + j], Y[i + j], X[i], Y[i], X[i + N_PTS - 1], Y[i + N_PTS - 1]));
    if max_dist > DIST then
    begin
      EvaluateLIC7 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC8: boolean;
var
  i: integer;
begin
  EvaluateLIC8 := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - K_PTS - 1 do
  begin
    if Distance(i, i + K_PTS + 1) > LENGTH1 then
    begin
      EvaluateLIC8 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC9: boolean;
var
  i: integer;
begin
  EvaluateLIC9 := false;
  if NUMPOINTS < 5 then
    Exit;
  for i := 1 to NUMPOINTS - A_PTS - B_PTS - 2 do
  begin
    if CircleRadius(i, i + A_PTS + 1, i + A_PTS + B_PTS + 2) > RADIUS1 then
    begin
      EvaluateLIC9 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC10: boolean;
var
  i: integer;
  angle: real;
begin
  EvaluateLIC10 := false;
  if NUMPOINTS < 5 then
    Exit;
  for i := 1 to NUMPOINTS - C_PTS - D_PTS - 2 do
  begin
    angle := Angle(i, i + C_PTS + 1, i + C_PTS + D_PTS + 2);
    if angle < 0 then
      continue;
    if (angle < (PI - EPSILON)) or (angle > (PI + EPSILON)) then
    begin
      EvaluateLIC10 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC11: boolean;
var
  i: integer;
begin
  EvaluateLIC11 := false;
  if NUMPOINTS < 5 then
    Exit;
  for i := 1 to NUMPOINTS - E_PTS - F_PTS - 2 do
  begin
    if TriangleArea(i, i + E_PTS + 1, i + E_PTS + F_PTS + 2) > AREA1 then
    begin
      EvaluateLIC11 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC12: boolean;
var
  i: integer;
begin
  EvaluateLIC12 := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - G_PTS - 1 do
  begin
    if X[i + G_PTS + 1] - X[i] < 0 then
    begin
      EvaluateLIC12 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC13: boolean;
var
  i: integer;
  has_greater, has_less: boolean;
begin
  EvaluateLIC13 := false;
  if NUMPOINTS < 3 then
    Exit;
  has_greater := false;
  has_less := false;
  for i := 1 to NUMPOINTS - K_PTS - 1 do
  begin
    if Distance(i, i + K_PTS + 1) > LENGTH1 then
      has_greater := true;
    if Distance(i, i + K_PTS + 1) < LENGTH2 then
      has_less := true;
  end;
  EvaluateLIC13 := has_greater and has_less;
end;

function EvaluateLIC14: boolean;
var
  i: integer;
  has_outside, has_inside: boolean;
begin
  EvaluateLIC14 := false;
  if NUMPOINTS < 5 then
    Exit;
  has_outside := false;
  has_inside := false;
  for i := 1 to NUMPOINTS - A_PTS - B_PTS - 2 do
  begin
    if CircleRadius(i, i + A_PTS + 1, i + A_PTS + B_PTS + 2) > RADIUS1 then
      has_outside := true;
    if CircleRadius(i, i + A_PTS + 1, i + A_PTS + B_PTS + 2) <= RADIUS2 then
      has_inside := true;
  end;
  EvaluateLIC14 := has_outside and has_inside;
end;

function EvaluateLIC15: boolean;
var
  i: integer;
  has_greater, has_less: boolean;
begin
  EvaluateLIC15 := false;
  if NUMPOINTS < 5 then
    Exit;
  has_greater := false;
  has_less := false;
  for i := 1 to NUMPOINTS - E_PTS - F_PTS - 2 do
  begin
    if TriangleArea(i, i + E_PTS + 1, i + E_PTS + F_PTS + 2) > AREA1 then
      has_greater := true;
    if TriangleArea(i, i + E_PTS + 1, i + E_PTS + F_PTS + 2) < AREA2 then
      has_less := true;
  end;
  EvaluateLIC15 := has_greater and has_less;
end;

procedure DECIDE;
var
  i, j: integer;
  all_true: boolean;
begin
  CMV[1] := EvaluateLIC1;
  CMV[2] := EvaluateLIC2;
  CMV[3] := EvaluateLIC3;
  CMV[4] := EvaluateLIC4;
  CMV[5] := EvaluateLIC5;
  CMV[6] := EvaluateLIC6;
  CMV[7] := EvaluateLIC7;
  CMV[8] := EvaluateLIC8;
  CMV[9] := EvaluateLIC9;
  CMV[10] := EvaluateLIC10;
  CMV[11] := EvaluateLIC11;
  CMV[12] := EvaluateLIC12;
  CMV[13] := EvaluateLIC13;
  CMV[14] := EvaluateLIC14;
  CMV[15] := EvaluateLIC15;

  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i = j then
      begin
        PUM[i, j] := false;
      end
      else if LCM[i, j] = NOTUSED then
        PUM[i, j] := true
      else if LCM[i, j] = ANDD then
        PUM[i, j] := CMV[i] and CMV[j]
      else if LCM[i, j] = ORR then
        PUM[i, j] := CMV[i] or CMV[j];
    end;
  end;

  for i := 1 to 15 do
  begin
    all_true := true;
    for j := 1 to 15 do
    begin
      if not PUM[i, j] then
        all_true := false;
    end;
    if (PUM[i, i] = false) or all_true then
      FUV[i] := true
    else
      FUV[i] := false;
  end;

  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      Exit;
    end;
  end;
end;

constructor TCharStream.Create(const S: string);
begin
  inherited Create;
  FData := S;
  FPos := 1;
end;

procedure TCharStream.SkipWhitespace;
begin
  while (FPos <= Length(FData)) and (FData[FPos] in [' ', #9, #10, #13]) do
    Inc(FPos);
end;

function TCharStream.PeekChar: char;
begin
  SkipWhitespace;
  if FPos > Length(FData) then
    Result := #0
  else
    Result := FData[FPos];
end;

function TCharStream.ReadChar: char;
begin
  SkipWhitespace;
  if FPos > Length(FData) then
    Result := #0
  else
  begin
    Result := FData[FPos];
    Inc(FPos);
  end;
end;

function TCharStream.ReadNumber: real;
var
  NumStr, ExpStr: string;
  Sign: integer;
  i: integer;
  HasDot, HasExp: boolean;
begin
  SkipWhitespace;
  Sign := 1;
  if FData[FPos] = '-' then
  begin
    Sign := -1;
    Inc(FPos);
  end
  else if FData[FPos] = '+' then
    Inc(FPos);

  NumStr := '';
  HasDot := false;
  while (FPos <= Length(FData)) and ((FData[FPos] in ['0'..'9']) or (FData[FPos] = '.')) do
  begin
    if FData[FPos] = '.' then
    begin
      HasDot := true;
      Inc(FPos);
    end
    else
    begin
      NumStr := NumStr + FData[FPos];
      Inc(FPos);
    end;
  end;

  ExpStr := '';
  if (FPos <= Length(FData)) and (FData[FPos] in ['e', 'E']) then
  begin
    ExpStr := 'e';
    Inc(FPos);
    if (FPos <= Length(FData)) and (FData[FPos] in ['+', '-']) then
    begin
      ExpStr := ExpStr + FData[FPos];
      Inc(FPos);
    end;
    while (FPos <= Length(FData)) and (FData[FPos] in ['0'..'9']) do
    begin
      ExpStr := ExpStr + FData[FPos];
      Inc(FPos);
    end;
  end;

  Result := StrToFloat(NumStr) * Power(10, StrToFloat(ExpStr)) * Sign;
end;

function TCharStream.ReadInteger: integer;
var
  NumStr: string;
  Sign: integer;
begin
  SkipWhitespace;
  Sign := 1;
  if FData[FPos] = '-' then
  begin
    Sign := -1;
    Inc(FPos);
  end
  else if FData[FPos] = '+' then
    Inc(FPos);

  NumStr := '';
  while (FPos <= Length(FData)) and (FData[FPos] in ['0'..'9']) do
  begin
    NumStr := NumStr + FData[FPos];
    Inc(FPos);
  end;

  Result := StrToInt(NumStr) * Sign;
end;

function TCharStream.ReadBoolean: boolean;
var
  Word: string;
  i: integer;
begin
  SkipWhitespace;
  Word := '';
  while (FPos <= Length(FData)) and (FData[FPos] in ['a'..'z', 'A'..'Z']) do
  begin
    Word := Word + LowerCase(FData[FPos]);
    Inc(FPos);
  end;
  Result := Word = 'true';
end;

function TCharStream.ReadString: string;
var
  Ch: char;
begin
  Ch := ReadChar;
  if Ch <> '"' then
    Exit;
  Result := '';
  while (FPos <= Length(FData)) and (FData[FPos] <> '"') do
  begin
    if FData[FPos] = '\' then
    begin
      Inc(FPos);
      if FPos <= Length(FData) then
        Result := Result + FData[FPos];
    end
    else
      Result := Result + FData[FPos];
    Inc(FPos);
  end;
  if FPos <= Length(FData) then
    Inc(FPos);
end;

function TCharStream.ReadArray: string;
var
  Ch: char;
  Items: TStringList;
begin
  Items := TStringList.Create;
  try
    Ch := ReadChar;
    if Ch <> '[' then
      Exit;
    while True do
    begin
      SkipWhitespace;
      Ch := PeekChar;
      if Ch = ']' then
      begin
        ReadChar;
        Break;
      end;
      if Ch = '"' then
        Items.Add(ReadString)
      else if Ch in ['0'..'9', '-', '+'] then
        Items.Add(FloatToStr(ReadNumber))
      else if Ch = 't' or Ch = 'f' then
        Items.Add(BooleanToStr(ReadBoolean))
      else if Ch = '[' then
        Items.Add(TCharStream.Create(FData).ReadArray)
      else if Ch = '{' then
      begin
        Inc(FPos);
        Items.Add(TCharStream.Create(FData).ReadObject);
      end;
      SkipWhitespace;
      Ch := PeekChar;
      if Ch = ',' then
        ReadChar;
    end;
    Result := Items.CommaText;
  finally
    Items.Free;
  end;
end;

function TCharStream.ReadObject: string;
var
  Ch: char;
  Key, Value: string;
  Items: TStringList;
begin
  Items := TStringList.Create;
  try
    Ch := ReadChar;
    if Ch <> '{' then
      Exit;
    while True do
    begin
      SkipWhitespace;
      Ch := PeekChar;
      if Ch = '}' then
      begin
        ReadChar;
        Break;
      end;
      Key := ReadString;
      SkipWhitespace;
      Ch := ReadChar;
      if Ch = ':' then
      begin
        SkipWhitespace;
        Ch := PeekChar;
        if Ch = '"' then
          Value := ReadString
        else if Ch in ['0'..'9', '-', '+'] then
          Value := FloatToStr(ReadNumber)
        else if Ch = 't' or Ch = 'f' then
          Value := BooleanToStr(ReadBoolean)
        else if Ch = '[' then
          Value := ReadArray
        else if Ch = '{' then
        begin
          Inc(FPos);
          Value := ReadObject;
        end;
        Items.Add(Key + ':' + Value);
      end;
      SkipWhitespace;
      Ch := PeekChar;
      if Ch = ',' then
        ReadChar;
    end;
    Result := '{' + Items.CommaText + '}';
  finally
    Items.Free;
  end;
end;

function TCharStream.Eof: boolean;
begin
  SkipWhitespace;
  Result := FPos > Length(FData);
end;

procedure ParseJSONInput(const JSONStr: string);
var
  Stream: TCharStream;
  J: string;
  i, j, idx: integer;
  Key, Val: string;
  LCMStr: string;
  PUMStr: string;
  ParamStream: TCharStream;
begin
  Stream := TCharStream.Create(JSONStr);
  try
    J := Stream.ReadObject;
    ParamStream := TCharStream.Create(J);

    Key := ''; Val := '';
    while not ParamStream.Eof do
    begin
      Key := ParamStream.ReadString;
      ParamStream.SkipWhitespace;
      ParamStream.ReadChar;
      ParamStream.SkipWhitespace;
      Val := ParamStream.ReadString;
      if Key = 'numpoints' then
        NUMPOINTS := StrToInt(Val);
    end;

    ParamStream := TCharStream.Create(J);
    Key := ''; Val := '';
    while not ParamStream.Eof do
    begin
      Key := ParamStream.ReadString;
      if Key = 'x' then
      begin
        Val := ParamStream.ReadString;
        idx := 1;
        for i := 1 to Length(Val) do
          if Val[i] = ',' then
            Inc(idx);
      end;
    end;

    ParamStream := TCharStream.Create(J);
    Key := ''; Val := '';
    while not ParamStream.Eof do
    begin
      Key := ParamStream.ReadString;
      ParamStream.SkipWhitespace;
      ParamStream.ReadChar;
      ParamStream.SkipWhitespace;
      if Key = 'x' then
      begin
        Val := ParamStream.ReadString;
        idx := 1;
        for i := 1 to Length(Val) do
        begin
          if Val[i] in ['0'..'9', '-', '.', '+'] then
          begin
            NumStr := '';
            while (i <= Length(Val)) and (Val[i] in ['0'..'9', '-', '.', '+']) do
            begin
              NumStr := NumStr + Val[i];
              Inc(i);
            end;
            X[idx] := StrToFloat(NumStr);
            Dec(i);
            Inc(idx);
          end
          else if Val[i] = ',' then
            Inc(idx);
        end;
      end
      else if Key = 'y' then
      begin
        Val := ParamStream.ReadString;
        idx := 1;
        for i := 1 to Length(Val) do
        begin
          if Val[i] in ['0'..'9', '-', '.', '+'] then
          begin
            NumStr := '';
            while (i <= Length(Val)) and (Val[i] in ['0'..'9', '-', '.', '+']) do
            begin
              NumStr := NumStr + Val[i];
              Inc(i);
            end;
            Y[idx] := StrToFloat(NumStr);
            Dec(i);
            Inc(idx);
          end
          else if Val[i] = ',' then
            Inc(idx);
        end;
      end
      else if Key = 'parameters' then
      begin
        ParamStream.SkipWhitespace;
        ParamStream.ReadChar;
        ParamStream.SkipWhitespace;
        LCMStr := ParamStream.ReadString;
        ParamStream := TCharStream.Create(LCMStr);
        Key := ''; Val := '';
        while not ParamStream.Eof do
        begin
          Key := ParamStream.ReadString;
          ParamStream.SkipWhitespace;
          ParamStream.ReadChar;
          ParamStream.SkipWhitespace;
          Val := ParamStream.ReadString;
          case Key of
            'LENGTH1': LENGTH1 := StrToFloat(Val);
            'RADIUS1': RADIUS1 := StrToFloat(Val);
            'EPSILON': EPSILON := StrToFloat(Val);
            'AREA1': AREA1 := StrToFloat(Val);
            'Q_PTS': Q_PTS := StrToInt(Val);
            'QUADS': QUADS := StrToInt(Val);
            'DIST': DIST := StrToFloat(Val);
            'N_PTS': N_PTS := StrToInt(Val);
            'K_PTS': K_PTS := StrToInt(Val);
            'A_PTS': A_PTS := StrToInt(Val);
            'B_PTS': B_PTS := StrToInt(Val);
            'C_PTS': C_PTS := StrToInt(Val);
            'D_PTS': D_PTS := StrToInt(Val);
            'E_PTS': E_PTS := StrToInt(Val);
            'F_PTS': F_PTS := StrToInt(Val);
            'G_PTS': G_PTS := StrToInt(Val);
            'LENGTH2': LENGTH2 := StrToFloat(Val);
            'RADIUS2': RADIUS2 := StrToFloat(Val);
            'AREA2': AREA2 := StrToFloat(Val);
          end;
        end;
      end;
    end;

    ParamStream := TCharStream.Create(J);
    Key := ''; Val := '';
    while not ParamStream.Eof do
    begin
      Key := ParamStream.ReadString;
      ParamStream.SkipWhitespace;
      ParamStream.ReadChar;
      ParamStream.SkipWhitespace;
      if Key = 'lcm' then
      begin
        Val := ParamStream.ReadString;
        idx := 0;
        for i := 1 to Length(Val) do
        begin
          if Val[i] = '"' then
          begin
            Inc(i);
            LCMStr := '';
            while (i <= Length(Val)) and (Val[i] <> '"') do
            begin
              LCMStr := LCMStr + Val[i];
              Inc(i);
            end;
            if LCMStr = 'NOTUSED' then
              LCM[idx div 15 + 1, idx mod 15 + 1] := NOTUSED
            else if LCMStr = 'ORR' then
              LCM[idx div 15 + 1, idx mod 15 + 1] := ORR
            else
              LCM[idx div 15 + 1, idx mod 15 + 1] := ANDD;
            Inc(idx);
          end;
        end;
      end
      else if Key = 'pum_diag' then
      begin
        Val := ParamStream.ReadString;
        idx := 0;
        for i := 1 to Length(Val) do
        begin
          if Val[i] = 't' then
          begin
            PUM[idx + 1, idx + 1] := true;
            Inc(idx);
          end
          else if Val[i] = 'f' then
          begin
            PUM[idx + 1, idx + 1] := false;
            Inc(idx);
          end;
        end;
      end;
    end;
  finally
    Stream.Free;
  end;
end;

function GenerateJSONOutput: string;
var
  i, j: integer;
  OutStr: string;
begin
  OutStr := '{"cmv":[';
  for i := 1 to 15 do
  begin
    if i > 1 then OutStr := OutStr + ',';
    if CMV[i] then OutStr := OutStr + 'true' else OutStr := OutStr + 'false';
  end;
  OutStr := OutStr + '],"pum":[';
  for i := 1 to 15 do
  begin
    if i > 1 then OutStr := OutStr + ',';
    OutStr := OutStr + '[';
    for j := 1 to 15 do
    begin
      if j > 1 then OutStr := OutStr + ',';
      if PUM[i, j] then OutStr := OutStr + 'true' else OutStr := OutStr + 'false';
    end;
    OutStr := OutStr + ']';
  end;
  OutStr := OutStr + '],"fuv":[';
  for i := 1 to 15 do
  begin
    if i > 1 then OutStr := OutStr + ',';
    if FUV[i] then OutStr := OutStr + 'true' else OutStr := OutStr + 'false';
  end;
  OutStr := OutStr + '],"launch":';
  if LAUNCH then
    OutStr := OutStr + 'true'
  else
    OutStr := OutStr + 'false';
  OutStr := OutStr + '}';
  Result := OutStr;
end;

var
  InputStr: string;
  OutputStr: string;
  Line: string;
  NumStr: string;
begin
  Line := '';
  while Readln(Line) do
    Line := Line + #10;
  if Length(Line) > 0 then
    Delete(Line, Length(Line), 1);
  InputStr := Line;

  ParseJSONInput(InputStr);
  DECIDE;
  OutputStr := GenerateJSONOutput;
  WriteLn(OutputStr);
end.

program LaunchInterceptor;

uses
  SysUtils;

const
  PI = 3.1415926535;

type
  COMPTYPE = (LT, EQ, GT);
  CONNECTORS = (NOTUSED, ORR, ANDD);
  COORDINATE = array[1..100] of real;
  CMATRIX = array[1..15, 1..15] of CONNECTORS;
  BMATRIX = array[1..15, 1..15] of boolean;
  VECTOR = array[1..15] of boolean;

var
  X, Y: COORDINATE;
  NUMPOINTS: integer;
  LENGTH1, RADIUS1, EPSILON, AREA1, DIST: real;
  Q_PTS, QUADS: integer;
  N_PTS, K_PTS, A_PTS, B_PTS, C_PTS, D_PTS, E_PTS, F_PTS, G_PTS: integer;
  LENGTH2, RADIUS2, AREA2: real;
  LCM: CMATRIX;
  PUM: BMATRIX;
  CMV: VECTOR;
  FUV: VECTOR;
  LAUNCH: boolean;
  InputData: string;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

function Distance(i, j: integer): real;
begin
  Distance := Sqrt(Sqr(X[i] - X[j]) + Sqr(Y[i] - Y[j]));
end;

function TriangleArea(i, j, k: integer): real;
begin
  TriangleArea := 0.5 * Abs((X[j] - X[i]) * (Y[k] - Y[i]) - (X[k] - X[i]) * (Y[j] - Y[i]));
end;

function Angle(i, j, k: integer): real;
var
  dx1, dy1, dx2, dy2, mag1, mag2, dot: real;
begin
  dx1 := X[i] - X[j];
  dy1 := Y[i] - Y[j];
  dx2 := X[k] - X[j];
  dy2 := Y[k] - Y[j];
  mag1 := Sqrt(Sqr(dx1) + Sqr(dy1));
  mag2 := Sqrt(Sqr(dx2) + Sqr(dy2));
  if (mag1 = 0) or (mag2 = 0) then
  begin
    Angle := -1;
    Exit;
  end;
  dot := dx1 * dx2 + dy1 * dy2;
  Angle := ArcTan2(dot, mag1 * mag2);
  if Angle < 0 then
    Angle := -Angle;
end;

function CircleRadius(i, j, k: integer): real;
var
  a, b, c, s, area: real;
begin
  a := Distance(j, k);
  b := Distance(i, k);
  c := Distance(i, j);
  if (a = 0) or (b = 0) or (c = 0) then
  begin
    CircleRadius := 0;
    Exit;
  end;
  s := (a + b + c) / 2;
  area := Sqrt(s * (s - a) * (s - b) * (s - c));
  if area = 0 then
  begin
    CircleRadius := 0;
    Exit;
  end;
  CircleRadius := (a * b * c) / (4 * area);
end;

function Quadrant(x, y: real): integer;
begin
  if (x > 0) and (y >= 0) then
    Quadrant := 1
  else if (x <= 0) and (y > 0) then
    Quadrant := 2
  else if (x < 0) and (y <= 0) then
    Quadrant := 3
  else
    Quadrant := 1;
end;

function EvaluateLIC1: boolean;
var
  i: integer;
begin
  EvaluateLIC1 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if Distance(i, i + 1) > LENGTH1 then
    begin
      EvaluateLIC1 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC2: boolean;
var
  i: integer;
begin
  EvaluateLIC2 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if CircleRadius(i, i + 1, i + 2) > RADIUS1 then
    begin
      EvaluateLIC2 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC3: boolean;
var
  i: integer;
  angle: real;
begin
  EvaluateLIC3 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    angle := Angle(i, i + 1, i + 2);
    if angle < 0 then
      continue;
    if (angle < (PI - EPSILON)) or (angle > (PI + EPSILON)) then
    begin
      EvaluateLIC3 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC4: boolean;
var
  i: integer;
begin
  EvaluateLIC4 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if TriangleArea(i, i + 1, i + 2) > AREA1 then
    begin
      EvaluateLIC4 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC5: boolean;
var
  i, quad_count, q1, q2, q3, q4: integer;
begin
  EvaluateLIC5 := false;
  for i := 1 to NUMPOINTS - Q_PTS + 1 do
  begin
    q1 := 0; q2 := 0; q3 := 0; q4 := 0;
    case Quadrant(X[i], Y[i]) of
      1: q1 := 1;
      2: q2 := 1;
      3: q3 := 1;
      4: q4 := 1;
    end;
    for j := 1 to Q_PTS - 1 do
      case Quadrant(X[i + j], Y[i + j]) of
        1: q1 := 1;
        2: q2 := 1;
        3: q3 := 1;
        4: q4 := 1;
      end;
    quad_count := q1 + q2 + q3 + q4;
    if quad_count > QUADS then
    begin
      EvaluateLIC5 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC6: boolean;
var
  i: integer;
begin
  EvaluateLIC6 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if X[i + 1] - X[i] < 0 then
    begin
      EvaluateLIC6 := true;
      Exit;
    end;
  end;
end;

function PointToLineDistance(px, py, x1, y1, x2, y2: real): real;
var
  dx, dy, num: real;
begin
  dx := x2 - x1;
  dy := y2 - y1;
  if (dx = 0) and (dy = 0) then
  begin
    PointToLineDistance := Sqrt(Sqr(px - x1) + Sqr(py - y1));
    Exit;
  end;
  num := Abs(dy * px - dx * py + x2 * y1 - y2 * x1);
  PointToLineDistance := num / Sqrt(Sqr(dx) + Sqr(dy));
end;

function EvaluateLIC7: boolean;
var
  i, j: integer;
  max_dist: real;
begin
  EvaluateLIC7 := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - N_PTS + 1 do
  begin
    max_dist := 0;
    for j := 0 to N_PTS - 1 do
      max_dist := Max(max_dist, PointToLineDistance(X[i + j], Y[i + j], X[i], Y[i], X[i + N_PTS - 1], Y[i + N_PTS - 1]));
    if max_dist > DIST then
    begin
      EvaluateLIC7 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC8: boolean;
var
  i: integer;
begin
