  if NUMPOINTS < 5 then
    Exit;
  for i := 1 to NUMPOINTS - A_PTS - B_PTS - 2 do
  begin
    if CircleRadius(i, i + A_PTS + 1, i + A_PTS + B_PTS + 2) > RADIUS1 then
    begin
      EvaluateLIC9 := true;
      Exit;
    end;
  end;
end;

function EvaluateLIC10: boolean;
var
  i: integer;
  angle: real;
  skip: boolean;
begin
  EvaluateLIC10 := false;
  if NUMPOINTS < 5 then
    Exit;
  for i := 1 to NUMPOINTS - C_PTS - D_PTS - 2 do
  begin
    angle := CalcAngle(i, i + C_PTS + 1, i + C_PTS + D_PTS + 2);
    skip := false;
    if angle < 0.0 then
      skip := true;
    if not skip then
    begin
      if (angle < (PI - EPSILON)) or (angle > (PI + EPSILON)) then
      begin
        EvaluateLIC10 := true;
        Exit;
      end;
    end;
  end;
end;

function EvaluateLIC11: boolean;
var
  i: integer;
begin
  EvaluateLIC11 := false;
  if NUMPOINTS < 5 then
