  has_greater := false;
  has_less := false;
  for i := 1 to NUMPOINTS - E_PTS - F_PTS - 2 do
  begin
    if TriangleArea(i, i + E_PTS + 1, i + E_PTS + F_PTS + 2) > AREA1 then
      has_greater := true;
    if TriangleArea(i, i + E_PTS + 1, i + E_PTS + F_PTS + 2) < AREA2 then
      has_less := true;
  end;
  EvaluateLIC15 := has_greater and has_less;
end;

procedure DECIDE;
var
  i, j: integer;
  all_true: boolean;
begin
  CMV[1] := EvaluateLIC1;
  CMV[2] := EvaluateLIC2;
  CMV[3] := EvaluateLIC3;
  CMV[4] := EvaluateLIC4;
  CMV[5] := EvaluateLIC5;
  CMV[6] := EvaluateLIC6;
  CMV[7] := EvaluateLIC7;
  CMV[8] := EvaluateLIC8;
  CMV[9] := EvaluateLIC9;
  CMV[10] := EvaluateLIC10;
  CMV[11] := EvaluateLIC11;
  CMV[12] := EvaluateLIC12;
  CMV[13] := EvaluateLIC13;
  CMV[14] := EvaluateLIC14;
  CMV[15] := EvaluateLIC15;

  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i = j then
      begin
        PUM[i, j] := false;
      end
      else if LCM[i, j] = NOTUSED then
        PUM[i, j] := true
      else if LCM[i, j] = ANDD then
        PUM[i, j] := CMV[i] and CMV[j]
      else if LCM[i, j] = ORR then
        PUM[i, j] := CMV[i] or CMV[j];
    end;
  end;

  for i := 1 to 15 do
  begin
    all_true := true;
    for j := 1 to 15 do
    begin
      if not PUM[i, j] then
        all_true := false;
    end;
    if (PUM[i, i] = false) or all_true then
      FUV[i] := true
    else
      FUV[i] := false;
  end;

  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      Exit;
    end;
  end;
end;

procedure SkipWhitespace;
begin
  while (StreamPos <= Length(InputData)) and (InputData[StreamPos] in [' ', #9, #10, #13]) do
    Inc(StreamPos);
end;

function PeekChar: char;
begin
  SkipWhitespace;
  if StreamPos > Length(InputData) then
    Result := #0
  else
    Result := InputData[StreamPos];
end;

function ReadChar: char;
var
  Ch: char;
begin
  SkipWhitespace;
  if StreamPos > Length(InputData) then
    Result := #0
  else
  begin
    Result := InputData[StreamPos];
    Inc(StreamPos);
  end;
end;

function ReadNumber: real;
var
  NumStr: string;
  Sign: integer;
begin
  SkipWhitespace;
  Sign := 1;
  if InputData[StreamPos] = '-' then
  begin
    Sign := -1;
    Inc(StreamPos);
  end
  else if InputData[StreamPos] = '+' then
    Inc(StreamPos);

  NumStr := '';
  while (StreamPos <= Length(InputData)) and (InputData[StreamPos] in ['0'..'9', '.', 'e', 'E', '+', '-']) do
  begin
    NumStr := NumStr + InputData[StreamPos];
    Inc(StreamPos);
  end;

  Result := StrToFloat(NumStr) * Sign;
end;

function ReadInteger: integer;
var
  NumStr: string;
  Sign: integer;
begin
  SkipWhitespace;
  Sign := 1;
  if InputData[StreamPos] = '-' then
  begin
    Sign := -1;
    Inc(StreamPos);
  end
  else if InputData[StreamPos] = '+' then
    Inc(StreamPos);

  NumStr := '';
  while (StreamPos <= Length(InputData)) and (InputData[StreamPos] in ['0'..'9']) do
  begin
    NumStr := NumStr + InputData[StreamPos];
    Inc(StreamPos);
  end;

  Result := StrToInt(NumStr) * Sign;
end;

function ReadString: string;
var
  Ch: char;
begin
  Ch := ReadChar;
  if Ch <> '"' then
    Exit;
  Result := '';
  while (StreamPos <= Length(InputData)) and (InputData[StreamPos] <> '"') do
  begin
    if InputData[StreamPos] = '\' then
    begin
      Inc(StreamPos);
      if StreamPos <= Length(InputData) then
        Result := Result + InputData[StreamPos];
    end
    else
      Result := Result + InputData[StreamPos];
    Inc(StreamPos);
  end;
  if StreamPos <= Length(InputData) then
    Inc(StreamPos);
end;

function ReadBoolean: boolean;
var
  Word: string;
  i: integer;
begin
  SkipWhitespace;
  Word := '';
  while (StreamPos <= Length(InputData)) and (InputData[StreamPos] in ['a'..'z', 'A'..'Z']) do
  begin
    Word := Word + LowerCase(InputData[StreamPos]);
    Inc(StreamPos);
  end;
  Result := Word = 'true';
end;

procedure ReadArray(var CoordArray: COORDINATE; var ArrayLen: integer);
var
  Ch: char;
  idx: integer;
begin
  Ch := ReadChar;
  if Ch <> '[' then
    Exit;
  idx := 1;
  while True do
  begin
    SkipWhitespace;
    Ch := PeekChar;
    if Ch = ']' then
    begin
      ReadChar;
      Break;
    end;
    if Ch in ['0'..'9', '-', '+', '.'] then
    begin
      CoordArray[idx] := ReadNumber;
      Inc(idx);
    end;
    SkipWhitespace;
    Ch := PeekChar;
    if Ch = ',' then
      ReadChar;
  end;
  ArrayLen := idx - 1;
end;

procedure ReadStringArray;
var
  Ch: char;
  Key: string;
  LCMRow, LCMCol: integer;
begin
  Ch := ReadChar;
  if Ch <> '[' then
    Exit;
  LCMRow := 0;
  while True do
  begin
    SkipWhitespace;
    Ch := PeekChar;
    if Ch = ']' then
    begin
      ReadChar;
      Break;
    end;
    if Ch = '[' then
    begin
      Inc(LCMRow);
      LCMCol := 0;
      ReadChar;
      while True do
      begin
        SkipWhitespace;
        Ch := PeekChar;
        if Ch = ']' then
        begin
          ReadChar;
          Break;
        end;
        Key := ReadString;
        if Key = 'NOTUSED' then
          LCM[LCMRow, LCMCol + 1] := NOTUSED
        else if Key = 'ORR' then
          LCM[LCMRow, LCMCol + 1] := ORR
        else if Key = 'ANDD' then
          LCM[LCMRow, LCMCol + 1] := ANDD;
        Inc(LCMCol);
        SkipWhitespace;
        Ch := PeekChar;
        if Ch = ',' then
          ReadChar;
      end;
    end;
    SkipWhitespace;
    Ch := PeekChar;
    if Ch = ',' then
      ReadChar;
  end;
end;

procedure ReadBooleanArray(var BoolArray: VECTOR);
var
  Ch: char;
  idx: integer;
begin
  Ch := ReadChar;
  if Ch <> '[' then
    Exit;
  idx := 1;
  while True do
  begin
    SkipWhitespace;
    Ch := PeekChar;
    if Ch = ']' then
    begin
      ReadChar;
      Break;
    end;
    BoolArray[idx] := ReadBoolean;
    Inc(idx);
    SkipWhitespace;
    Ch := PeekChar;
    if Ch = ',' then
      ReadChar;
  end;
end;

procedure ReadObject;
var
  Ch: char;
  Key: string;
begin
  Ch := ReadChar;
  if Ch <> '{' then
    Exit;
  while True do
  begin
    SkipWhitespace;
    Ch := PeekChar;
    if Ch = '}' then
    begin
      ReadChar;
      Break;
    end;
    Key := ReadString;
    SkipWhitespace;
    Ch := ReadChar;
    if Ch = ':' then
    begin
      SkipWhitespace;
      Ch := PeekChar;
      if Key = 'numpoints' then
      begin
        NUMPOINTS := ReadInteger;
      end
      else if Key = 'x' then
      begin
        ReadArray(X, NUMPOINTS);
      end
      else if Key = 'y' then
      begin
        ReadArray(Y, NUMPOINTS);
      end
      else if Key = 'parameters' then
      begin
        ReadObject;
      end
      else if Key = 'lcm' then
      begin
        ReadStringArray;
      end
      else if Key = 'pum_diag' then
      begin
        ReadBooleanArray(PUM);
      end
      else
      begin
        Ch := ReadChar;
        if Ch = '{' then
        begin
          ReadObject;
        end
        else if Ch = '[' then
        begin
          if Key = 'x' or Key = 'y' then
          begin
            // Already handled above
          end
          else
          begin
            // Skip array
            while True do
            begin
              SkipWhitespace;
              Ch := PeekChar;
              if Ch = ']' then
              begin
                ReadChar;
                Break;
              end;
              if Ch = '{' then
                ReadObject
              else if Ch = '[' then
              begin
                while True do
                begin
                  SkipWhitespace;
                  Ch := PeekChar;
                  if Ch = ']' then
                  begin
                    ReadChar;
                    Break;
                  end;
                  if Ch = '{' then
                    ReadObject
                  else if Ch in ['0'..'9', '-', '.'] then
                    ReadNumber
                  else if Ch = '"' then
                    ReadString
                  else if Ch = 't' or Ch = 'f' then
                    ReadBoolean
                  else
                    Inc(StreamPos);
                end;
              end
              else if Ch in ['0'..'9', '-', '.'] then
                ReadNumber
              else if Ch = '"' then
                ReadString
              else if Ch = 't' or Ch = 'f' then
                ReadBoolean
              else
                Inc(StreamPos);
            end;
          end;
        end
        else if Ch in ['0'..'9', '-', '.'] then
        begin
          if Key = 'LENGTH1' then LENGTH1 := ReadNumber
          else if Key = 'RADIUS1' then RADIUS1 := ReadNumber
          else if Key = 'EPSILON' then EPSILON := ReadNumber
          else if Key = 'AREA1' then AREA1 := ReadNumber
          else if Key = 'Q_PTS' then Q_PTS := ReadInteger
          else if Key = 'QUADS' then QUADS := ReadInteger
          else if Key = 'DIST' then DIST := ReadNumber
          else if Key = 'N_PTS' then N_PTS := ReadInteger
          else if Key = 'K_PTS' then K_PTS := ReadInteger
          else if Key = 'A_PTS' then A_PTS := ReadInteger
          else if Key = 'B_PTS' then B_PTS := ReadInteger
          else if Key = 'C_PTS' then C_PTS := ReadInteger
          else if Key = 'D_PTS' then D_PTS := ReadInteger
          else if Key = 'E_PTS' then E_PTS := ReadInteger
          else if Key = 'F_PTS' then F_PTS := ReadInteger
          else if Key = 'G_PTS' then G_PTS := ReadInteger
          else if Key = 'LENGTH2' then LENGTH2 := ReadNumber
          else if Key = 'RADIUS2' then RADIUS2 := ReadNumber
          else if Key = 'AREA2' then AREA2 := ReadNumber;
        end
        else if Ch = '"' then
        begin
          ReadString;
        end
        else if Ch = 't' or Ch = 'f' then
        begin
          ReadBoolean;
        end
        else if Ch = '{' then
        begin
          ReadObject;
        end
        else if Ch = '[' then
        begin
          // Skip array
          while True do
          begin
            SkipWhitespace;
            Ch := PeekChar;
            if Ch = ']' then
            begin
              ReadChar;
              Break;
            end;
            if Ch = '{' then
              ReadObject
            else if Ch in ['0'..'9', '-', '.'] then
              ReadNumber
            else if Ch = '"' then
              ReadString
            else if Ch = 't' or Ch = 'f' then
              ReadBoolean
            else
              Inc(StreamPos);
          end;
        end
        else
          Inc(StreamPos);
      end;
    end;
    SkipWhitespace;
    Ch := PeekChar;
    if Ch = ',' then
      ReadChar;
  end;
end;

procedure ParseJSONInput(const JSONStr: string);
begin
  InputData := JSONStr;
  StreamPos := 1;
  ReadObject;
end;

function GenerateJSONOutput: string;
var
  i, j: integer;
  OutStr: string;
begin
  OutStr := '{"cmv":[';
  for i := 1 to 15 do
  begin
    if i > 1 then OutStr := OutStr + ',';
    if CMV[i] then OutStr := OutStr + 'true' else OutStr := OutStr + 'false';
  end;
  OutStr := OutStr + '],"pum":[';
  for i := 1 to 15 do
  begin
    if i > 1 then OutStr := OutStr + ',';
    OutStr := OutStr + '[';
    for j := 1 to 15 do
    begin
      if j > 1 then OutStr := OutStr + ',';
      if PUM[i, j] then OutStr := OutStr + 'true' else OutStr := OutStr + 'false';
    end;
    OutStr := OutStr + ']';
  end;
  OutStr := OutStr + '],"fuv":[';
  for i := 1 to 15 do
  begin
    if i > 1 then OutStr := OutStr + ',';
    if FUV[i] then OutStr := OutStr + 'true' else OutStr := OutStr + 'false';
  end;
  OutStr := OutStr + '],"launch":';
  if LAUNCH then
    OutStr := OutStr + 'true'
  else
    OutStr := OutStr + 'false';
  OutStr := OutStr + '}';
  GenerateJSONOutput := OutStr;
end;

var
  InputStr: string;
  OutputStr: string;
  Line: string;
begin
  Line := '';
  while not Eof do
  begin
    Readln(Line);
  end;
  InputStr := Line;

  ParseJSONInput(InputStr);
  DECIDE;
  OutputStr := GenerateJSONOutput;
  WriteLn(OutputStr);
end.

