  SkipWhitespace;
  if StreamPos > Length(InputData) then
    Result := #0
  else
  begin
    Result := InputData[StreamPos];
    Inc(StreamPos);
  end;
end;

function ReadNumber: real;
var
  NumStr: string;
  Sign: integer;
begin
  SkipWhitespace;
  Sign := 1;
  if InputData[StreamPos] = '-' then
  begin
    Sign := -1;
    Inc(StreamPos);
  end
  else if InputData[StreamPos] = '+' then
    Inc(StreamPos);

  NumStr := '';
  while (StreamPos <= Length(InputData)) and (InputData[StreamPos] in ['0'..'9', '.', 'e', 'E', '+', '-']) do
  begin
    NumStr := NumStr + InputData[StreamPos];
    Inc(StreamPos);
  end;

  Result := StrToFloat(NumStr) * Sign;
end;

function ReadInteger: integer;
var
  NumStr: string;
  Sign: integer;
begin
  SkipWhitespace;
  Sign := 1;
  if InputData[StreamPos] = '-' then
  begin
    Sign := -1;
    Inc(StreamPos);
  end
  else if InputData[StreamPos] = '+' then
    Inc(StreamPos);

  NumStr := '';
  while (StreamPos <= Length(InputData)) and (InputData[StreamPos] in ['0'..'9']) do
  begin
    NumStr := NumStr + InputData[StreamPos];
    Inc(StreamPos);
  end;

  Result := StrToInt(NumStr) * Sign;
end;

function ReadString: string;
var
  Ch: char;
begin
  Ch := ReadChar;
  if Ch <> '"' then
    Exit;
  Result := '';
  while (StreamPos <= Length(InputData)) and (InputData[StreamPos] <> '"') do
  begin
    if InputData[StreamPos] = '\' then
    begin
      Inc(StreamPos);
      if StreamPos <= Length(InputData) then
        Result := Result + InputData[StreamPos];
    end
    else
      Result := Result + InputData[StreamPos];
    Inc(StreamPos);
  end;
  if StreamPos <= Length(InputData) then
    Inc(StreamPos);
end;

function ReadBoolean: boolean;
var
  Word: string;
  i: integer;
begin
  SkipWhitespace;
  Word := '';
  while (StreamPos <= Length(InputData)) and (InputData[StreamPos] in ['a'..'z', 'A'..'Z']) do
  begin
    Word := Word + LowerCase(InputData[StreamPos]);
    Inc(StreamPos);
  end;
  Result := Word = 'true';
end;

procedure ReadArray;
var
  Ch: char;
  idx: integer;
begin
  Ch := ReadChar;
  if Ch <> '[' then
    Exit;
  idx := 1;
  while True do
  begin
    SkipWhitespace;
    Ch := PeekChar;
    if Ch = ']' then
    begin
      ReadChar;
      Break;
    end;
    if Ch in ['0'..'9', '-', '+', '.'] then
    begin
      WriteLn('Reading number: ', ReadNumber);
      Inc(idx);
    end;
    SkipWhitespace;
    Ch := PeekChar;
    if Ch = ',' then
      ReadChar;
  end;
end;

procedure ReadObject;
var
  Ch: char;
  Key: string;
begin
  Ch := ReadChar;
  if Ch <> '{' then
  begin
    WriteLn('Expected {, got: ', Ch);
    Exit;
  end;
  WriteLn('Started object');
  while True do
  begin
    SkipWhitespace;
    Ch := PeekChar;
    if Ch = '}' then
    begin
      ReadChar;
      Break;
    end;
    Key := ReadString;
    WriteLn('Key: ', Key);
    SkipWhitespace;
    Ch := ReadChar;
    if Ch = ':' then
    begin
      SkipWhitespace;
      Ch := PeekChar;
      WriteLn('Value char: ', Ch);
      if Ch = '{' then
      begin
        WriteLn('Nested object');
        ReadObject;
      end
      else if Ch = '[' then
      begin
        WriteLn('Array');
        ReadArray;
      end
      else if Ch in ['0'..'9', '-', '.'] then
      begin
        WriteLn('Number: ', ReadNumber);
      end
      else if Ch = '"' then
      begin
        WriteLn('String: ', ReadString);
      end
      else if Ch = 't' or Ch = 'f' then
      begin
        WriteLn('Boolean: ', ReadBoolean);
      end
      else
        Inc(StreamPos);
    end;
    SkipWhitespace;
    Ch := PeekChar;
    if Ch = ',' then
      ReadChar;
  end;
  WriteLn('Ended object');
end;

procedure ParseJSONInput(const JSONStr: string);
begin
  InputData := JSONStr;
  StreamPos := 1;
  ReadObject;
end;

var
  InputStr: string;
  Line: string;
begin
  Line := '';
  while not Eof do
  begin
    Readln(Line);
  end;
  InputStr := Line;
  ParseJSONInput(InputStr);
  WriteLn('Done');
end.
ENDOFFILE
